const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const session = require('express-session');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);

const sessionMiddleware = session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    httpOnly: true,
    sameSite: 'lax',
    secure: false,
    maxAge: 1000 * 60 * 60 * 24
  }
});

app.use(express.json());
app.use(sessionMiddleware);

const io = new Server(server, {
  cors: {
    origin: true,
    credentials: true
  }
});

io.use((socket, next) => {
  sessionMiddleware(socket.request, {}, next);
});

const PORT = process.env.PORT || 3000;

const users = new Map();
const players = new Map();
const leaderboard = new Map();
const rooms = new Map();

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const clean = username.trim();
  if (!/^[a-zA-Z0-9_]{3,20}$/.test(clean)) return null;
  return clean;
}

function hashPassword(password, salt = crypto.randomBytes(16).toString('hex')) {
  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return { salt, hash };
}

function verifyPassword(password, salt, hash) {
  const test = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return crypto.timingSafeEqual(Buffer.from(test, 'hex'), Buffer.from(hash, 'hex'));
}

function requireAuth(req, res, next) {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

function getTopScores(limit = 10) {
  return [...leaderboard.entries()]
    .map(([username, score]) => ({ username, score }))
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}

function safePlayerState(player) {
  return {
    id: player.id,
    username: player.username,
    roomId: player.roomId,
    position: player.position,
    score: player.score,
    connected: player.connected
  };
}

app.post('/register', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  const password = typeof req.body.password === 'string' ? req.body.password : '';

  if (!username || password.length < 8) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }

  if (users.has(username)) {
    return res.status(409).json({ error: 'Username already exists' });
  }

  const { salt, hash } = hashPassword(password);
  const userId = crypto.randomUUID();

  users.set(username, {
    id: userId,
    username,
    salt,
    hash,
    createdAt: Date.now()
  });

  req.session.userId = userId;
  req.session.username = username;

  return res.json({ success: true, user: { id: userId, username } });
});

app.post('/login', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  const password = typeof req.body.password === 'string' ? req.body.password : '';

  if (!username || !users.has(username)) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const user = users.get(username);

  if (!verifyPassword(password, user.salt, user.hash)) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  req.session.userId = user.id;
  req.session.username = user.username;

  return res.json({ success: true, user: { id: user.id, username: user.username } });
});

app.post('/logout', requireAuth, (req, res) => {
  req.session.destroy(() => {
    res.json({ success: true });
  });
});

app.get('/me', requireAuth, (req, res) => {
  res.json({
    user: {
      id: req.session.userId,
      username: req.session.username
    }
  });
});

app.get('/leaderboard', (req, res) => {
  res.json({ leaderboard: getTopScores(50) });
});

function ensureRoom(roomId) {
  if (!rooms.has(roomId)) {
    rooms.set(roomId, {
      id: roomId,
      players: new Set()
    });
  }
  return rooms.get(roomId);
}

io.use((socket, next) => {
  const req = socket.request;
  if (!req.session || !req.session.userId || !req.session.username) {
    return next(new Error('Unauthorized'));
  }
  next();
});

io.on('connection', (socket) => {
  const req = socket.request;
  const userId = req.session.userId;
  const username = req.session.username;

  const existingPlayer = players.get(userId);
  if (existingPlayer) {
    existingPlayer.socketId = socket.id;
    existingPlayer.connected = true;
  } else {
    players.set(userId, {
      id: userId,
      username,
      socketId: socket.id,
      roomId: null,
      position: { x: 0, y: 0 },
      score: leaderboard.get(username) || 0,
      connected: true,
      lastUpdateAt: Date.now()
    });
  }

  socket.emit('connected', {
    player: safePlayerState(players.get(userId)),
    leaderboard: getTopScores()
  });

  socket.on('join_room', (payload = {}) => {
    const roomId = typeof payload.roomId === 'string' && payload.roomId.trim()
      ? payload.roomId.trim().slice(0, 50)
      : 'default';

    const player = players.get(userId);
    if (!player) return;

    if (player.roomId) {
      socket.leave(player.roomId);
      const oldRoom = rooms.get(player.roomId);
      if (oldRoom) {
        oldRoom.players.delete(userId);
      }
    }

    const room = ensureRoom(roomId);
    room.players.add(userId);
    player.roomId = roomId;

    socket.join(roomId);

    const roomPlayers = [...room.players]
      .map((id) => players.get(id))
      .filter(Boolean)
      .map(safePlayerState);

    socket.emit('room_joined', { roomId, players: roomPlayers });
    socket.to(roomId).emit('player_joined', { player: safePlayerState(player) });
  });

  socket.on('move', (payload = {}) => {
    const player = players.get(userId);
    if (!player || !player.roomId) return;

    const x = Number(payload.x);
    const y = Number(payload.y);

    if (!Number.isFinite(x) || !Number.isFinite(y)) return;

    player.position = { x, y };
    player.lastUpdateAt = Date.now();

    socket.to(player.roomId).emit('player_moved', {
      id: player.id,
      username: player.username,
      position: player.position
    });
  });

  socket.on('score_update', (payload = {}) => {
    const player = players.get(userId);
    if (!player) return;

    const score = Number(payload.score);
    if (!Number.isFinite(score) || score < 0) return;

    player.score = score;
    const currentTop = leaderboard.get(username) || 0;
    if (score > currentTop) {
      leaderboard.set(username, score);
    }

    io.emit('leaderboard_update', {
      leaderboard: getTopScores()
    });
  });

  socket.on('get_room_players', () => {
    const player = players.get(userId);
    if (!player || !player.roomId) {
      return socket.emit('room_players', { players: [] });
    }

    const room = rooms.get(player.roomId);
    const roomPlayers = room
      ? [...room.players]
          .map((id) => players.get(id))
          .filter(Boolean)
          .map(safePlayerState)
      : [];

    socket.emit('room_players', { players: roomPlayers });
  });

  socket.on('disconnect', () => {
    const player = players.get(userId);
    if (!player) return;

    player.connected = false;

    if (player.roomId) {
      socket.to(player.roomId).emit('player_left', {
        id: player.id,
        username: player.username
      });
    }
  });
});

server.listen(PORT, () => {
  console.log(`Game server running on port ${PORT}`);
});